    {
      "span_start": 258,
      "span_end": 300,
      "span_text": "إِنَّ إِبْرَاهِيمَ لَحَلِيمٌ أَوَّاهٌ مُنِيبٌ",
      "citation_type": "Aya"
    },
    {
      "span_start": 350,
      "span_end": 378,
      "span_text": "فَبَشَّرْنَاهُ بِغُلَامٍ حَلِيمٍ",
      "citation_type": "Aya"
    },
    {
      "span_start": 450,
      "span_end": 520,
      "span_text": "قَالَ يَا قَوْمِ لَيْسَ بِي سَفَاهَةٌ وَلَكِنِّي رَسُولٌ مِنْ رَبِّ الْعَالَمِينَ * أُبَلِّغُكُمْ رِسَالَاتِ رَبِّي وَأَنَا لَكُمْ نَاصِحٌ أَمِينٌ",
      "citation_type": "Aya"
    },
    {
      "span_start": 600,
      "span_end": 624,
      "span_text": "إن إبراهيم لأواه حليم",
      "citation_type": "Aya"
    },
    {
      "span_start": 630,
      "span_end": 659,
      "span_text": "وإن إبراهيم لحليم أوّاه منيب",
      "citation_type": "Aya"
    },
    {
      "span_start": 700,
      "span_end": 728,
      "span_text": "فَبَشَّرْنَاهُ بِغُلَامٍ حَلِيمٍ",
      "citation_type": "Aya"
    },
    {
      "span_start": 750,
      "span_end": 805,
      "span_text": "إِنَّا لَنَرَاكَ فِي سَفَاهَةٍ وَإِنَّا لَنَظُنُّكَ مِنَ الْكَاذِبِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 810,
      "span_end": 900,
      "span_text": "فَلَمَّا بَلَغَ مَعَهُ السَّعْيَ قَالَ يَا بُنَيَّ إِنِّي أَرَى فِي الْمَنَامِ أَنِّي أَذْبُحَكَ فَانْظُرْ مَاذَا تَرَى قَالَ يَا أَبَتِ افْعَلْ مَا تُؤْمَرْ سَتَجِدُنِي إِنْ شَاءَ اللَّهُ مِنَ الصَّابِريِنَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 910,
      "span_end": 950,
      "span_text": "سَتَجِدُنِي إِنْ شَاءَ اللَّهُ مِنَ الصَّابِرِينَ",
      "citation_type": "Aya"
    },
    {
      "span_start": 1000,
      "span_end": 1040,
      "span_text": "إِنِّي أَرَى فِي الْمَنَامِ أَنِّي أَذْبُحُكَ",
      "citation_type": "Aya"
    }
  ]
}
